import { Router } from "express";
import { acceptSetupInvitation, change, completeReset, login, logout, register, reset, validateSetupInvitation } from "../controllers/authController.js";
import { requireAuth, requireRole } from "../middleware/auth.js";
import { authLimiter } from "../middleware/rateLimiter.js";
const router = Router();
router.post("/login", authLimiter, login);
router.post("/register", authLimiter, requireAuth, requireRole("hr"), register);
router.post("/logout", requireAuth, logout);
router.post("/reset-password", authLimiter, reset);
router.post("/reset-password/complete", authLimiter, completeReset);
router.get("/invitations/validate", authLimiter, validateSetupInvitation);
router.post("/invitations/accept", authLimiter, acceptSetupInvitation);
router.post("/change-password", requireAuth, change);
export default router;
